(window.webpackJsonp=window.webpackJsonp||[]).push([[1192],{1461:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">S</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">indexes</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string[]}</span> <span class=\\"hljs-variable\\">sources</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string[]}</span> <span class=\\"hljs-variable\\">targets</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{string}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findReplaceString = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">S, indexes, sources, targets</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> newS=<span class=\\"hljs-string\\">\'\'</span>\\n  <span class=\\"hljs-keyword\\">let</span> endID=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> auxIdx=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;indexes.length;i++){\\n    auxIdx[i]=[indexes[i],i]\\n  }\\n  auxIdx.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>])\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;auxIdx.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [id,initI]=auxIdx[i]\\n    <span class=\\"hljs-keyword\\">let</span> s=sources[initI],t=targets[initI]\\n    newS+=S.substring(endID,id)\\n    endID=id+s.length\\n    <span class=\\"hljs-keyword\\">let</span> inits=S.substring(id,endID)\\n    <span class=\\"hljs-keyword\\">if</span>(inits===s){\\n      newS+=t\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      newS+=inits\\n    }\\n  }\\n  newS+=S.substring(endID)\\n  <span class=\\"hljs-keyword\\">return</span> newS\\n};\\n</code></pre>\\n"],"titleSlug":"find-and-replace-in-string","hasThinking":false,"content":"<p>\u67d0\u4e2a\u5b57\u7b26\u4e32 <code>S</code> \u9700\u8981\u6267\u884c\u4e00\u4e9b\u66ff\u6362\u64cd\u4f5c\uff0c\u7528\u65b0\u7684\u5b57\u6bcd\u7ec4\u66ff\u6362\u539f\u6709\u7684\u5b57\u6bcd\u7ec4\uff08\u4e0d\u4e00\u5b9a\u5927\u5c0f\u76f8\u540c\uff09\u3002</p>\\n\\n<p>\u6bcf\u4e2a\u66ff\u6362\u64cd\u4f5c\u5177\u6709 3 \u4e2a\u53c2\u6570\uff1a\u8d77\u59cb\u7d22\u5f15 <code>i</code>\uff0c\u6e90\u5b57 <code>x</code> \u548c\u76ee\u6807\u5b57 <code>y</code>\u3002\u89c4\u5219\u662f\uff1a\u5982\u679c <code>x</code> \u4ece<strong>\u539f\u59cb\u5b57\u7b26\u4e32 <code>S</code></strong> \u4e2d\u7684\u4f4d\u7f6e <code>i</code> \u5f00\u59cb\uff0c\u90a3\u4e48\u5c31\u7528 <code>y</code> \u66ff\u6362\u51fa\u73b0\u7684 <code>x</code>\u3002\u5982\u679c\u6ca1\u6709\uff0c\u5219\u4ec0\u4e48\u90fd\u4e0d\u505a\u3002</p>\\n\\n<p>\u4e3e\u4e2a\u4f8b\u5b50\uff0c\u5982\u679c <code>S\xa0= \u201cabcd\u201d</code> \u5e76\u4e14\u66ff\u6362\u64cd\u4f5c <code>i = 2\uff0cx = \u201ccd\u201d\uff0cy = \u201cffff\u201d</code>\uff0c\u90a3\u4e48\u56e0\u4e3a <code>\u201ccd\u201d</code> \u4ece\u539f\u59cb\u5b57\u7b26\u4e32 <code>S</code> \u4e2d\u7684\u4f4d\u7f6e <code>2</code> \u5f00\u59cb\uff0c\u6240\u4ee5\u7528\xa0<code>\u201cffff\u201d</code> \u66ff\u6362\u5b83\u3002</p>\\n\\n<p>\u518d\u6765\u770b <code>S = \u201cabcd\u201d</code> \u4e0a\u7684\u53e6\u4e00\u4e2a\u4f8b\u5b50\uff0c\u5982\u679c\u4e00\u4e2a\u66ff\u6362\u64cd\u4f5c<code> i = 0\uff0cx = \u201cab\u201d\uff0cy = \u201ceee\u201d</code>\uff0c\u4ee5\u53ca\u53e6\u4e00\u4e2a\u66ff\u6362\u64cd\u4f5c <code>i = 2\uff0cx = \u201cec\u201d\uff0cy = \u201cffff\u201d</code>\uff0c\u90a3\u4e48\u7b2c\u4e8c\u4e2a\u64cd\u4f5c\u5c06\u4e0d\u4f1a\u6267\u884c\uff0c\u56e0\u4e3a\u539f\u59cb\u5b57\u7b26\u4e32\u4e2d\xa0<code>S[2] = \'c\'</code>\uff0c\u4e0e <code>x[0] = \'e\'</code> \u4e0d\u5339\u914d\u3002</p>\\n\\n<p>\u6240\u6709\u8fd9\u4e9b\u64cd\u4f5c\u540c\u65f6\u53d1\u751f\u3002\u4fdd\u8bc1\u5728\u66ff\u6362\u65f6\u4e0d\u4f1a\u6709\u4efb\u4f55\u91cd\u53e0\uff1a\xa0<code>S = \\"abc\\", indexes = [0, 1],\xa0sources = [\\"ab\\",\\"bc\\"]</code> \u4e0d\u662f\u6709\u6548\u7684\u6d4b\u8bd5\u7528\u4f8b\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>S = \\"abcd\\", indexes = [0,2], sources = [\\"a\\",\\"cd\\"], targets = [\\"eee\\",\\"ffff\\"]\\n<strong>\u8f93\u51fa\uff1a</strong>\\"eeebffff\\"\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\\"a\\" \u4ece S \u4e2d\u7684\u7d22\u5f15 0 \u5f00\u59cb\uff0c\u6240\u4ee5\u5b83\u88ab\u66ff\u6362\u4e3a \\"eee\\"\u3002\\n\\"cd\\" \u4ece S \u4e2d\u7684\u7d22\u5f15 2 \u5f00\u59cb\uff0c\u6240\u4ee5\u5b83\u88ab\u66ff\u6362\u4e3a \\"ffff\\"\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>S = \\"abcd\\", indexes = [0,2], sources = [\\"ab\\",\\"ec\\"], targets = [\\"eee\\",\\"ffff\\"]\\n<strong>\u8f93\u51fa\uff1a</strong>\\"eeecd\\"\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\\"ab\\" \u4ece S \u4e2d\u7684\u7d22\u5f15 0 \u5f00\u59cb\uff0c\u6240\u4ee5\u5b83\u88ab\u66ff\u6362\u4e3a \\"eee\\"\u3002\\n\\"ec\\" \u6ca1\u6709\u4ece<strong>\u539f\u59cb\u7684</strong> S \u4e2d\u7684\u7d22\u5f15 2 \u5f00\u59cb\uff0c\u6240\u4ee5\u5b83\u6ca1\u6709\u88ab\u66ff\u6362\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= S.length <= 1000</code></li>\\n\\t<li><code>S</code> \u4ec5\u7531\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u7ec4\u6210</li>\\n\\t<li><code>0 <= indexes.length <= 100</code></li>\\n\\t<li><code>0 <= indexes[i] < S.length</code></li>\\n\\t<li><code>sources.length == indexes.length</code></li>\\n\\t<li><code>targets.length == indexes.length</code></li>\\n\\t<li><code>1 <= sources[i].length, targets[i].length <= 50</code></li>\\n\\t<li><code>sources[i]</code> \u548c <code>targets[i]</code> \u4ec5\u7531\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u7ec4\u6210</li>\\n</ul>\\n\\n<p>\xa0</p>\\n","title":"833. \u5b57\u7b26\u4e32\u4e2d\u7684\u67e5\u627e\u4e0e\u66ff\u6362","relatedTags":["\u5b57\u7b26\u4e32"],"difficult":"Middle","lang":["javascript"],"uniqueID":"833"}')}}]);